VALUES
  ('optometrist-moex-01934', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '某近視硬式透氣隱形眼鏡度數-8.00 DS，其鏡片透氧率（Dk）大於50 ，則預估鏡片中心厚度在下列何者 之間？', '["0.11to0.15mm", "0.16to0.20mm", "0.21to0.25mm", "0.26to0.30mm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01935', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜弧度測量儀，下列何者錯誤？', '["角膜弧度儀，是一項容易操作、簡單非侵入性的檢查，是驗配隱形眼鏡一個重要的步驟", "可以測量角膜屈光度、角膜散光和晶體散光", "主要測量角膜中心3mm的地方，甚至更大範圍", "測出的屈光度是來自角膜前表面"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01936', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配戴硬式隱形眼鏡時，若以細隙燈的藍光觀察，在角膜上皮受傷的地方可看到黃綠色的角膜上皮螢光染色， 有關角膜上皮螢光染色的敘述，下列何者錯誤？', '["若在周邊角膜3點和9點鐘的位置發現有螢光染色的現象，以鏡片的機械性摩擦以及角膜乾燥所引起的 較為常見", "角膜變形（cornealwarpage），一般會有角膜染色", "在鏡片邊緣呈現三角形的角膜染色區塊，是眨眼時沒有被淚水覆蓋到的地方", "如改變硬式隱形眼鏡設計，減少鏡片與周邊角膜的接觸及增加淚液交換，可能改善周邊染色情形"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01937', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴隱形眼鏡後角膜上皮水腫造成的所謂中央角膜混濁（centralcornealclouding）的敘述，下列何者 錯誤？', '["通常會造成角膜弧度變陡（steepening）", "通常會造成近視度數加深", "通常是聚甲基丙烯酸甲酯（polymethylmethacrylate，PMMA）材質的比較會發生", "通常病人換戴一般眼鏡會覺得比戴隱形眼鏡清楚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01938', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於角膜螢光染色形態和隱形眼鏡對於眼表面的影響，下列配對敘述何者最正確？', '["瀰漫性點狀角膜螢光染色（diffusepunctatestaining）：角膜乾燥（cornealdesiccation）", "線狀角膜螢光染色（linearcornealstaining）：角膜缺氧（cornealhypoxia）", "面紗狀淺凹角膜螢光染色（dimpleveilstaing）：鏡片內陷氣泡造成角膜壓跡", "角膜3點和9點位置螢光染色（3and9o''clockstaining）：隱形眼鏡清潔液毒性（solutionsensitivity）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01939', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡引起的角膜新生血管常見的啟動因子（initiatingfactors）敘述，下列何者錯誤？', '["造成角膜的發炎細胞（inflammatorycells）增加", "活化需氧代謝（aerobicmetabolism）", "刺激或傷害角膜上皮", "來不及代謝乳酸（lacticacid）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01940', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '長時間配戴矽水膠鏡片（silicone hydrogel lenses），對於在鏡片背面與角膜之間最容易出現的淚液層碎骸 （tearfilmdebris），我們稱為黏蛋白球（mucinballs），下列有關黏蛋白球的敘述何者錯誤？', '["黏蛋白球呈現珍珠色半透明顆粒狀或扁平甜甜圈狀（flatterneddoughnut）", "配戴硬式高透氣鏡片或水膠鏡片（hydrogellenses）可以降低黏蛋白球出現機率", "黏蛋白球會引發發炎或感染等嚴重併發症", "黏蛋白球的組成成分主要包括黏蛋白及油脂，在停戴隱形眼鏡後會消失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01941', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '角膜地圖儀檢查的研究顯示，幾乎所有種類的隱形眼鏡都有可能造成角膜翹曲變形（warpage），根據 NathanEfron 教科書上敘述，角膜翹曲主要發生於角膜的那一層組織？', '["表皮層（epithelium）", "鮑曼氏層（Bowman''smembrane）", "基質層（stroma）", "內皮細胞層（endothelium）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01942', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡的相關敘述，下列何者正確？', '["配戴隱形眼鏡時，眨眼的頻率會下降", "軟式隱形眼鏡較硬式隱形眼鏡更容易影響眨眼的模式（blinkingpattern）", "眼瞼刷上皮病變（lidwiperepitheliopathy）的成因為皮脂腺阻塞", "根據Korb等人研究，眼瞼刷上皮病變是乾眼症的一個診斷現象（diagnosticsign）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01943', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於隱形眼鏡的選擇，下列何者敘述正確？', '["根據美國FDA建議，游泳時建議使用長戴型軟式隱形眼鏡", "巨大乳突結膜炎（giant papillaryconjunctivitis）患者因度數無法使用一般日拋型隱形眼鏡，則建議選擇 低含水量非離子性隱形眼鏡（low-water-content,nonionic）", "角膜新生血管（cornealneovascularization）患者建議改用水膠隱形眼鏡", "乾眼症患者若必須使用隱形眼鏡，建議使用高含水量軟式隱形眼鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:50+00:00", "source_pdf_sha1": "e80981a1b26d", "answer_pdf_sha1": "58622d5953d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
